package uk.ac.ed.ltg.jdm.textdata;import java.util.Map;import org.apache.log4j.Logger;/** * This represents a large part of the document, typically larger than a * {@link Section}. */public class Zone extends AbstractElement {	/**	 * 	 */	private static final long serialVersionUID = 4817124097569663661L;	public static final String NAME = "zone";	/** The Constant logger. */	private static final Logger logger = Logger.getLogger(Zone.class);	/**	 * The Constructor.	 * 	 * @param document	 *            the document	 */	public Zone(final Document document) {		super(document);		// logger.debug("new Zone()");
	}	/**	 * Instantiates a new zone.	 * 	 * @param document	 *            the document	 * @param type	 *            the type	 */	public Zone(final Document document, final String type) {		super(document, null, type);	}	/**	 * The Constructor.	 * 	 * @param type	 *            the type	 * @param document	 *            the document	 * @param id	 *            the id	 */	public Zone(final Document document, final String id, final String type) {		super(document, id, type);		// logger.debug("new Zone(" + id + ",'" + type + "')");
	}	/**	 * The Constructor.	 * 	 * @param type	 *            the type	 * @param document	 *            the document	 * @param map	 *            the map	 * @param id	 *            the id	 */	public Zone(final Document document, final String id, final String type,			final Map map) {		super(document, id, type, map);		// logger.debug("new Zone(" + id + ",'" + type + "', attributes)");
	}	/**	 * The Constructor.	 * 	 * @param type	 *            the type	 * @param document	 *            the document	 * @param map	 *            the map	 * @param l	 *            the l	 * @param s	 *            the s	 * @param e	 *            the e	 * @param id	 *            the id	 */	public Zone(final Document document, final String id, final String type,			final Map map, final int s, final int e) {		super(document, id, type, map, s, e);		// logger.debug("new Zone(" + id + ",'" + type + "', attributes)");
	}	public String getName() {		return NAME;	}	@Override	public String toString() {		return this.getClass().getName() + "[" + this.getType() + "] ("				+ this.disjointSpan + ")";	}}